import React, { useState, useEffect, useRef } from 'react';

const ACCENT = '#FF9100';

const ROLES = [
  'Maestro Barbero',
  'Barbero Senior',
  'Barbero Junior',
  'Barbero Estilista',
  'Director de Arte',
  'Instructor',
];

const BRANCHES = ['Los Magallanes', 'Catia — Calle México', 'Ambas'];

const COLORS = ['#b8976a', '#7a9e7e', '#7a8fa0', '#9e7a7a', '#8a7a9e', '#a09060', '#6a8fa0'];

const EMPTY = {
  name: '', last: '', role: 'Maestro Barbero',
  phone: '', ig: '', exp: 1,
  skills: [], bio: '',
  status: 'active', branch: 'Los Magallanes',
  color: '#b8976a',
};

export default function BarberoForm({ open, onClose, onSave, initial }) {
  const [form, setForm] = useState(EMPTY);
  const [skillInput, setSkillInput] = useState('');
  const skillRef = useRef();

  useEffect(() => {
    if (open) {
      setForm(initial ? { ...initial } : { ...EMPTY });
      setSkillInput('');
    }
  }, [open, initial]);

  if (!open) return null;

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const addSkill = () => {
    const s = skillInput.trim();
    if (s && !form.skills.includes(s)) {
      set('skills', [...form.skills, s]);
    }
    setSkillInput('');
    skillRef.current?.focus();
  };

  const removeSkill = (i) => set('skills', form.skills.filter((_, idx) => idx !== i));

  const handleSkillKey = (e) => {
    if (e.key === 'Enter') { e.preventDefault(); addSkill(); }
    if (e.key === 'Backspace' && skillInput === '' && form.skills.length) {
      set('skills', form.skills.slice(0, -1));
    }
  };

  const handleSave = () => {
    if (!form.name.trim()) return;
    onSave(form);
  };

  return (
    <div style={overlay} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={modal}>
        {/* header */}
        <div style={modalHeader}>
          <span style={modalTitle}>{initial ? 'Editar Barbero' : 'Agregar Barbero'}</span>
          <button style={iconBtn} onClick={onClose}><i className="ti ti-x" /></button>
        </div>

        {/* body */}
        <div style={modalBody}>
          <div style={row2}>
            <Field label="Nombre">
              <input style={input} value={form.name} onChange={e => set('name', e.target.value)} placeholder="Carlos" />
            </Field>
            <Field label="Apellido">
              <input style={input} value={form.last} onChange={e => set('last', e.target.value)} placeholder="Rodríguez" />
            </Field>
          </div>

          <Field label="Rol / Especialidad">
            <select style={input} value={form.role} onChange={e => set('role', e.target.value)}>
              {ROLES.map(r => <option key={r}>{r}</option>)}
            </select>
          </Field>

          <div style={row2}>
            <Field label="Teléfono">
              <input style={input} value={form.phone} onChange={e => set('phone', e.target.value)} placeholder="+58 414 000 0000" />
            </Field>
            <Field label="Instagram">
              <input style={input} value={form.ig} onChange={e => set('ig', e.target.value)} placeholder="@usuario" />
            </Field>
          </div>

          <div style={row2}>
            <Field label="Años de experiencia">
              <input style={input} type="number" min="0" max="50"
                value={form.exp} onChange={e => set('exp', parseInt(e.target.value) || 0)} />
            </Field>
            <Field label="Sede">
              <select style={input} value={form.branch} onChange={e => set('branch', e.target.value)}>
                {BRANCHES.map(b => <option key={b}>{b}</option>)}
              </select>
            </Field>
          </div>

          {/* skills */}
          <Field label="Habilidades (Enter para agregar)">
            <div
              style={skillsBox}
              onClick={() => skillRef.current?.focus()}
            >
              {form.skills.map((s, i) => (
                <span key={i} style={{ ...skillTag, background: `${ACCENT}18`, color: ACCENT, border: `1px solid ${ACCENT}45` }}>
                  {s}
                  <button onClick={() => removeSkill(i)} style={skillDel}>×</button>
                </span>
              ))}
              <input
                ref={skillRef}
                style={skillInput2}
                value={skillInput}
                onChange={e => setSkillInput(e.target.value)}
                onKeyDown={handleSkillKey}
                placeholder={form.skills.length === 0 ? 'Fade, Diseño, Afeitado...' : ''}
              />
            </div>
          </Field>

          <Field label="Bio / Descripción">
            <textarea
              style={{ ...input, resize: 'vertical', minHeight: 72 }}
              value={form.bio}
              onChange={e => set('bio', e.target.value)}
              placeholder="Describe al barbero, su estilo y experiencia..."
            />
          </Field>

          {/* color */}
          <Field label="Color de acento">
            <div style={{ display: 'flex', gap: 8, marginTop: 2 }}>
              {COLORS.map(c => (
                <div
                  key={c}
                  onClick={() => set('color', c)}
                  style={{
                    width: 22, height: 22, borderRadius: '50%',
                    background: c, cursor: 'pointer',
                    border: ACCENT === c ? '2px solid var(--text)' : '2px solid transparent',
                    transition: 'border-color 0.15s',
                  }}
                />
              ))}
            </div>
          </Field>

          <Field label="Estado">
            <select style={input} value={form.status} onChange={e => set('status', e.target.value)}>
              <option value="active">Activo</option>
              <option value="inactive">Inactivo</option>
            </select>
          </Field>
        </div>

        {/* footer */}
        <div style={modalFooter}>
          <button style={btnCancel} onClick={onClose}>Cancelar</button>
          <button style={btnSave} onClick={handleSave}>
            {initial ? 'Guardar cambios' : 'Agregar barbero'}
          </button>
        </div>
      </div>
    </div>
  );
}

function Field({ label, children }) {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 5 }}>
